mainGridContainer(arr)

function mainGridContainer(arr) {
  let old = document.querySelector('.gridContainer')
  if (old) old.remove()
  let mainContainer = document.createElement('div')
  mainContainer.className = 'gridContainer '

  arr.map((e) => {
    let gridContainer = document.createElement('div')
    gridContainer.innerHTML = `   
            <div class="grid shadow-lg ">
               <img src="${e.car}" alt="" class="img-fluid">
               <h3>${e.name}</h3>
               <p>${e.Detail}</p>
            </div>      
            `
    mainContainer.append(gridContainer)
  })
  body.append(mainContainer)
}

mainGridContainer(arr)

let originalArr = [...arr]
let inputer = document.querySelector('.inputer')
let searcher = document.querySelector('.searcher')
searcher.addEventListener('click',()=>{
  let input = inputer.value.toLowerCase()
  let filter = originalArr.filter(e=>{
    return e.name.toLowerCase().includes(input)
  })
  if(input.includes(filter)){

    alert('Not Found')
  }else{
    mainGridContainer(filter)
    
  }


})


inputer.addEventListener('input',()=>{
  let input = inputer.value.toLowerCase()
   

  if(input === ''){ 
    mainGridContainer(arr)
  }

})

